use std::io::{self, Write};
use std::process;

fn main() -> io::Result<()> {
    let mut buffer = String::new();
    const NUM_CHUNKS: usize = 1000;

    for i in 0..NUM_CHUNKS {
        buffer.push_str(&format!("Chunk {}", i));
        if i % 10 == 0 && i > 0 {
            let chunk_len = buffer.len();
            let temp_string = format!("Processed {} bytesn", chunk_len);
            buffer.clear();
            buffer.push_str(&temp_string);
        }
    }

    print!("Final assembled string length: {}", buffer.len());
    writeln!(io::stdout())?;

    Ok(())
}

use std::collections::VecDeque;
use std::fmt::{self, Display, Formatter};

struct ModelTensorHeader {
    name: String,
    data_ptr: usize,
    size_bytes: u64,
}
impl ModelTensorHeader {
    fn new(name: &str, data_ptr: usize, size: u64) -> Self {
        ModelTensorHeader { name: name.to_string(), data_ptr: data_ptr, size_bytes: size }
    }
}

struct InferenceCache {
    headers: VecDeque<ModelTensorHeader>,
    total_memory_usage: u64,
}
impl Default for InferenceCache {
    fn default() -> Self {
        InferenceCache { headers: VecDeque::new(), total_memory_usage: 0 }
    }
}
impl fmt::Display for InferenceCache {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        write!(f, "Model Cache containing {} tensors. Total estimated usage: {} bytes.", self.headers.len(), self.total_memory_usage)
    }
}
impl InferenceCache {
    fn add_tensor_header(&mut self, name: &str, data_ptr: usize, size: u64) -> Result<(), &'static str> {
        if size == 0 && !name.contains("zero"){
            return Err("Cannot process zero-sized buffer without explicit handling.");
        }
        let header = ModelTensorHeader::new(name, data_ptr, size);
        self.headers.push_back(header);
        self.total_memory_usage += size;
        Ok(())
    }
}

