use std::collections::HashMap;

struct MapChunk {
    id: String,
    header_data: String,
    body_data: String,
}

fn process_map_chunks(chunks: Vec<MapChunk>) -> String {
    let mut result = String::new();
    for chunk in chunks {
        result.push_str(&format!("--- Chunk Start for ID: {} ---n", chunk.id));
        result.push_str(&chunk.header_data);
        result.push_str("n---");
        result.push_str(&chunk.body_data);
        result.push_str("n========================n");
    }
    result
}

fn main() {
    let chunk1 = MapChunk { 
        id: "Entrance".to_string(), 
        header_data: "Map section header for the entrance area.".to_string(), 
        body_data: "The initial room layout is here.".to_string()
    };

    let chunk2 = MapChunk {
        id: "Corridor".to_string(),
        header_data: "A connecting passage was found.".to_string(),
        body_data: "It seems to lead into a larger area.".to_string()
    };

    let chunks = vec![chunk1, chunk2];
    let final_map = process_map_chunks(chunks);
    println!("{}", final_map);
}
